extra.modelCss:
/* Dashboard (CSS do projeto) */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
  --radius: 14px;
  --shadow-1: 0 6px 16px rgba(0, 0, 0, 0.12);
  --shadow-2: 0 16px 40px rgba(0, 0, 0, 0.16);
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  line-height: 1.6;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 16px;
}

@media (min-width: 768px) {
  .container { padding: 24px; }
}

@media (min-width: 1024px) {
  .container { padding: 32px; }
}

.app-shell {
  display: grid;
  grid-template-columns: 1fr;
  grid-template-areas:
    "topbar"
    "sidebar"
    "main";
  gap: 16px;
  align-items: start;
}

.topbar {
  grid-area: topbar;
  position: sticky;
  top: 0;
  z-index: 10;
  background: rgba(11, 15, 25, 0.92);
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.topbar-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 16px;
}

.sidebar {
  grid-area: sidebar;
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.sidebar-inner {
  display: grid;
  gap: 8px;
  padding: 12px;
}

.nav-link {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 12px;
  color: var(--text);
  text-decoration: none;
}

.nav-link:hover {
  background: rgba(255, 255, 255, 0.04);
}

.nav-link:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.nav-link.active {
  color: var(--accent);
  background: rgba(96, 165, 250, 0.10);
  border: 1px solid rgba(96, 165, 250, 0.20);
}

.main {
  grid-area: main;
  display: grid;
  gap: 16px;
}

.stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-1);
}

.card-inner {
  padding: 16px;
  display: grid;
  gap: 10px;
}

.card.clickable {
  transition: transform 180ms ease, box-shadow 180ms ease;
}

.card.clickable:hover,
.card.clickable:focus-visible {
  transform: translateY(-2px);
  box-shadow: var(--shadow-2);
}

.table-card .table-wrap {
  overflow-x: auto;
}

.table-card table {
  width: 100%;
  border-collapse: collapse;
  min-width: 640px;
}

.table-card th,
.table-card td {
  text-align: left;
  padding: 10px 12px;
  border-bottom: 1px solid var(--border);
}

.muted {
  color: var(--muted);
}

@media (min-width: 1024px) {
  .app-shell {
    grid-template-columns: 280px 1fr;
    grid-template-areas:
      "topbar topbar"
      "sidebar main";
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    animation: none !important;
  }
}
